use std::error::Error;

struct TimeSeriesData {
    readings: Vec<f32>,
}

impl TimeSeriesData {
    fn new(readings: Vec<f32>) -> Self {
        TimeSeriesData { readings }
    }
}

fn calculate_sliding_z_score(data: &TimeSeriesData, window_size: usize) -> Result<Vec<f32>, Box<dyn Error>> {
    if data.readings.len() < window_size + 1 {
        return Ok(Vec::new());
    }

    let mut z_scores = Vec::with_capacity(data.readings.len() - window_size);

    for i in window_size..data.readings.len() {
        let current_value = data.readings[i];
        let window_start = (i + 1).checked_sub(window_size + 1).unwrap_or(0);
        let window = &data.readings[window_start..i];

        if window.is_empty() {
            z_scores.push(f32::NAN);
            continue;
        }

        let sum: f32 = window.iter().sum();
        let mean = sum / (window.len() as f32);

        let variance_sum: f32 = window.iter().map(|&x| (x - mean).powi(2)).sum();
        let std_dev = (variance_sum / (window.len() as f32)).sqrt();

        if std_dev == 0.0 {
            z_scores.push(0.0);
        } else {
            z_scores.push((current_value - mean) / std_dev);
        }
    }

    Ok(z_scores)
}

fn main() -> Result<(), Box<dyn Error>> {
    let raw_data = vec![10.1, 10.5, 9.8, 11.2, 12.0, 13.5, 14.0, 13.8, 12.5, 11.0, 10.9, 15.0, 16.0];
    let data = TimeSeriesData::new(raw_data);
    let window = 10;

    match calculate_sliding_z_score(&data, window) {
        Ok(scores) => {
            println!("Calculated Z-Scores:");
            for score in scores.iter() {
                println!("{:.4}", *score);
            }
        },
        Err(e) => {
            eprintln!("Error processing data: {}", e);
        }
    }
    Ok(())
}

use std::time::Instant;

#[derive(Clone)]
struct OptionParams {
    strike_price: f64,
    time_to_expiry: f64,
    risk_free_rate: f64,
}

fn calculate_payoff(s_t: f64, k: f64) -> f64 {
    (s_t - k).max(0.0)
}

fn monte_carlo_simulation(params: &OptionParams, num_paths: usize) -> f64 {
    let mut sum_log_returns = 0.0;
    for _ in 0..num_paths {
        let random_gaussian = rand::random::<f64>();
        let drift = (params.risk_free_rate - 0.5 * 0.0) * params.time_to_expiry;
        let diffusion = std::f64::consts::SQRT_2 * random_gaussian.sqrt() * params.time_to_expiry.max(1e-9);
        let s_t = 100.0 * (drift + diffusion).exp();
        sum_log_returns += s_t;
    }

    let average_payoff = sum_log_returns / num_paths as f64;
    average_payoff.sqrt()
}

fn main() {
    println!("Starting Monte Carlo Pricing Test...");
    let params = OptionParams {
        strike_price: 100.0,
        time_to_expiry: 1.0,
        risk_free_rate: 0.05,
    };

    let paths_small = 10_000;
    let start_small = Instant::now();
    let result_small = monte_carlo_simulation(&params, paths_small);
    let duration_small = start_small.elapsed();
    println!("Result with {} paths: {:.4} (Time: {:?})", paths_small, result_small, duration_small);

    let paths_large = 100_000_000;
    let start_large = Instant::now();
    let result_large = monte_carlo_simulation(&params, paths_large);
    let duration_large = start_large.elapsed();
    println!("Result with {} paths: {:.4} (Time: {:?})", paths_large, result_large, duration_large);
}

use std::collections::HashMap;

struct LogEntry {
    index: u64,
    term: i64,
    data: Vec<u8>,
}

struct ConsensusState {
    last_applied: u64,
    next_index: HashMap<i32, u64>,
    state_machine: HashMap<String, String>,
}

impl ConsensusState {
    fn new(node_id: i32) -> Self {
        ConsensusState {
            last_applied: 0,
            next_index: HashMap::from([(node_id, 1)]),
            state_machine: HashMap::new(),
        }
    }

    fn apply_log_entry(&mut self, entry: &LogEntry) -> Result<(), String> {
        if entry.index <= self.last_applied {
            return Err(format!("Already applied up to index {}", self.last_applied));
        }

        let key = format!("key_{}", entry.index);
        let value = format!("value_{}", entry.index);

        self.state_machine.insert(key, format!("processed {}", std::str::from_utf8(&entry.data).unwrap_or("invalid")));
        self.last_applied = entry.index;
        Ok(())
    }

    fn advance_next_index(&mut self, node_id: i32, new_next_index: u64) {
        if let Some(existing) = self.next_index.get_mut(&node_id) {
            *existing = new_next_index;
        } else {
            self.next_index.insert(node_id, new_next_index);
        }
    }
}

use std::collections::HashMap;

#[derive(Clone)]
struct TileEntity {
    id: u32,
    x_pos: i32,
    y_pos: i32,
    value: f32,
}

fn process_visible_entities(entities: &Vec<TileEntity>) -> HashMap<u32, (f32, i32)> {
    let mut results = HashMap::new();

    for entity in entities.iter() { 
        let id = entity.id; 
        let x_pos = entity.x_pos; 
        let y_pos = entity.y_pos;
        let value = entity.value;
        results.insert(id, (value, x_pos));
    }
    results
}

fn main() {
    let mut tile_data: Vec<TileEntity> = Vec::new();
    tile_data.push(TileEntity { id: 101, x_pos: 5, y_pos: 3, value: 1.5 });
    tile_data.push(TileEntity { id: 102, x_pos: 6, y_pos: 3, value: 2.0 });
    tile_data.push(TileEntity { id: 103, x_pos: 5, y_pos: 4, value: 0.8 });

    let processed_map = process_visible_entities(&tile_data);

    println!("Processed Map Entries:");
    for (id, (value, _x)) in &processed_map {
        println!("Entity ID: {}, Value: {:.2}", id, value);
    }
}

use std::collections::HashMap;
use std::thread;
use std::time::Duration;

struct JobResult {
    status: String,
    output: String,
}

fn run_isolated_job(job_id: u32) -> JobResult {
    println!("Starting job {}", job_id);
    thread::sleep(Duration::from_millis((job_id as u64 * 100) + 500));
    if job_id % 2 == 0 {
        JobResult {
            status: "Completed".to_string(),
            output: format!("Successfully processed data for job {}", job_id),
        }
    } else {
        thread::sleep(Duration::from_millis(300));
        JobResult {
            status: "Failed".to_string(),
            output: format!("Could not connect to resource for job {}", job_id),
        }
    }
}

fn main() {
    let mut active_jobs: HashMap<u32, thread::JoinHandle<JobResult>> = HashMap::new();
    let num_jobs = 5;

    for i in 1..=num_jobs {
        let handle = thread::spawn(move || run_isolated_job(i));
        active_jobs.insert(i, handle);
    }

    let mut final_report: HashMap<u32, JobResult> = HashMap::new();

    for (id, handle) in active_jobs.into_iter() {
        match handle.join() {
            Ok(result) => {
                final_report.insert(id, result);
            }
            Err(_) => {
                println!("Thread panicked for job {}", id);
                let failed_result = JobResult { status: "Panic".to_string(), output: format!("Job {} crashed", id) };
                final_report.insert(id, failed_result);
            }
        }
    }

    println!("n--- CI Pipeline Report ---");
    for (id, result) in final_report {
        println!("Job {}: Status: {}, Output: {}", id, result.status, result.output);
    }
}
